package com.alsa.alsacleanfleet.controller; import com.alsa.alsacleanfleet.dto.*;import com.alsa.alsacleanfleet.service.BusService;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/bus") public class BusController{private final BusService s;public BusController(BusService s){this.s=s;}@GetMapping public List<BusResponseDTO> all(){return s.findAll();}@GetMapping("/{id}")public BusResponseDTO one(@PathVariable Long id){return s.findById(id);}@PostMapping public ResponseEntity<BusResponseDTO> add(@Valid @RequestBody BusRequestDTO d){return ResponseEntity.status(HttpStatus.CREATED).body(s.create(d));}@PutMapping("/{id}")public BusResponseDTO edit(@PathVariable Long id,@Valid @RequestBody BusRequestDTO d){return s.update(id,d);}@DeleteMapping("/{id}")public ResponseEntity<Void> del(@PathVariable Long id){s.delete(id);return ResponseEntity.noContent().build();}}
